package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressYieldSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // yield_optimize_expression
  // =========================================================================
  test("yield_optimize_expression") {
    assertCompresses(
      input = """function* f1() { yield; }
        function* f2() { yield undefined; }
        function* f3() { yield null; }
        function* f4() { yield* undefined; }""".stripMargin.trim,
      expected = """function* f1() { yield }
        function* f2() { yield; }
        function* f3() { yield null; }
        function* f4() { yield* void 0; }""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // yield_as_identifier_in_function_in_generator
  // =========================================================================
  test("yield_as_identifier_in_function_in_generator") {
    assertCompresses(
      input = """var g = function*() {
            function h() {
                yield = 1;
            }
        }""".stripMargin.trim,
      expected = """var g = function*() {
            function h() {
                yield = 1;
            }
        }""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // yield_before_punctuators
  // =========================================================================
  test("yield_before_punctuators") {
    assertCompresses(
      input = """iter = (function*() {
            assignmentResult = [ x = yield ] = value;
        })();
        function* g1() { (yield) }
        function* g2() { [yield] }
        function* g3() { yield, yield; }
        function* g4() { (yield) ? yield : yield; }""".stripMargin.trim,
      expected = """iter = (function*() {
            assignmentResult = [ x = yield ] = value;
        })();
        function* g1() { (yield) }
        function* g2() { [yield] }
        function* g3() { yield, yield; }
        function* g4() { (yield) ? yield : yield; }""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // yield_as_identifier_outside_strict_mode
  // =========================================================================
  test("yield_as_identifier_outside_strict_mode") {
    assertCompresses(
      input = """import yield from "bar";
        yield = 123;
        while (true) {
            yield:
            for(;;) break yield;

            foo();
        }
        while (true)
            yield: for(;;) continue yield;
        function yield(){}
        function foo(...yield){}
        try { new Error("") } catch (yield) {}
        var yield = "foo"""".stripMargin.trim,
      expected = """import yield from "bar";
        yield = 123;
        while (true) {
            yield:
            for(;;) break yield;

            foo();
        }
        while (true)
            yield: for(;;) continue yield;
        function yield(){}
        function foo(...yield){}
        try { new Error("") } catch (yield) {}
        var yield = "foo"""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // issue_t60
  // =========================================================================
  test("issue_t60".fail) {
    assertCompresses(
      input = """function* t() {
            const v = yield 1;
            yield 2;
            return v;
        }
        var g = t();
        console.log(g.next().value, g.next().value)""".stripMargin.trim,
      expected = """function* t() {
            const v = yield 1;
            yield 2;
            return v;
        }
        var g = t();
        console.log(g.next().value, g.next().value)""".stripMargin.trim,
      options = AllOff.copy(
        collapseVars = true,
        sideEffects = true,
        unused = true
      )
    )
  }

}
